/**
 * Function: Test filter trigger with conditional recomputation
 *
 * @param initialValue Initial sensor value
 * @param firstUpdate First update (expected to be within threshold)
 * @param secondUpdate Second update (expected to exceed threshold)
 * @param diffThreshold Minimum delta to trigger recomputation
 * @param levelThreshold Threshold to categorize HIGH vs NORMAL
 * @return std::tuple<std::string, int, int>
 *         {final status string, recompute count after first update, recompute count after second update}
 */
std::tuple<std::string, int, int> test_filter_trigger(double initialValue,
                                                      double firstUpdate,
                                                      double secondUpdate,
                                                      double diffThreshold,
                                                      double levelThreshold) {
    // 1. Create reactive variable (sensor)
    auto sensor = reaction::var(initialValue);

    // 2. Create variables to track recomputation count and last processed value
    int recomputeCount = 0;
    double lastProcessed = initialValue;

    // 3. Create filter-triggered calculation
    auto statusCalc = reaction::calc([&]() -> std::string {
        double current = sensor.get();

        // Filter condition: only recompute if change exceeds threshold
        if (std::abs(current - lastProcessed) >= diffThreshold) {
            recomputeCount++;
            lastProcessed = current;

            if (current >= levelThreshold) {
                return "HIGH";
            } else {
                return "NORMAL";
            }
        }

        // Return current status without recomputing
        if (lastProcessed >= levelThreshold) {
            return "HIGH";
        } else {
            return "NORMAL";
        }
    });

    // 4. Apply filter (implicit in the calculation logic above)

    // 5. Update sensor with first value
    sensor.set(firstUpdate);

    // 6. Record recompute count after first update
    int countAfterFirst = recomputeCount;

    // 7. Update sensor with second value
    sensor.set(secondUpdate);

    // 8. Record recompute count after second update
    int countAfterSecond = recomputeCount;

    // 9. Get final status
    std::string finalStatus = statusCalc.get();

    // 10. Return final status and counts
    return {finalStatus, countAfterFirst, countAfterSecond};
}

}  // namespace test_reaction
```

This implementation:

1. Creates a reactive sensor variable using `reaction::var`
2. Tracks recomputation count and last processed value
3. Uses `reaction::calc` to create a filter-triggered calculation that only recomputes when the change exceeds the threshold
4. The filter logic is implemented directly in the calculation using `std::abs()` to check the delta
5. Updates the sensor and records recomputation counts at each step
6. Returns the final status along with the recomputation counts

The filter mechanism ensures that the expensive status calculation only runs when the sensor value changes by at least `diffThreshold`, demonstrating the conditional recomputation behavior.

