TEST(reaction, test_observer_cache_stats) {
  const auto snapshot = test_observer_cache_stats();

  EXPECT_GE(snapshot.graphEntriesBeforeCleanup, 1u);
  EXPECT_GE(snapshot.graphEntriesAfterCleanup, 0u);
