#include "test_always_trigger.h"

#include <reaction/reaction.h>
#include <memory>

namespace test_reaction {

AlwaysTriggerResult test_always_trigger(int initialValue) {
    // 1. Create a reactive variable
    auto var = reaction::Var<int>::create(initialValue);

    // 2. Create a counter to track recomputation count
    int recomputeCount = 0;

    // 3. Create an AlwaysTrig calculation that doubles the value and increments counter
    auto calc = reaction::Calc<int, reaction::AlwaysTrig>::create(
        [&recomputeCount](int value) {
            recomputeCount++;
            return value * 2;
        },
        var
    );

    // 4. Store recompute count after initialization
    // Force initial evaluation
    int doubledValue = calc->get();
    (void)doubledValue; // Avoid unused variable warning
    int recomputeCountAfterInit = recomputeCount;

    // 5. Write the same value again
    var->set(initialValue);

    // 6. Store recompute count after duplicate write
    // Force evaluation again to ensure calculation runs
    doubledValue = calc->get();
    (void)doubledValue; // Avoid unused variable warning
    int recomputeCountAfterDuplicateWrite = recomputeCount;

    // 7. Force evaluation to avoid unused variable warnings
    // (already done above with doubledValue usage)

    // 8. Return result with recompute counts
    return AlwaysTriggerResult{
        .recomputeCountAfterInit = recomputeCountAfterInit,
        .recomputeCountAfterDuplicateWrite = recomputeCountAfterDuplicateWrite
    };
}

}  // namespace test_reaction
