        report.guardAllocated = true;

        // Step 7: Get current usage during guard
        report.usageDuringGuard = StackMonitor::getCurrentUsage();

        // Step 8: Get statistics and Step 9: Store usage percentage and near limit flag
        // For statistics, we need to calculate based on available stack space
        // Using a reasonable assumption for stack limit (e.g., 1MB = 1048576 bytes)
        constexpr std::size_t STACK_LIMIT = 1048576;
        report.usagePercentage = (static_cast<double>(report.usageDuringGuard) / STACK_LIMIT) * 100.0;
        report.nearLimitDuringGuard = (report.usageDuringGuard > STACK_LIMIT * 0.9); // 90% of limit
    }
