        // 8. Check if guard succeeded
        snapshot.guardSucceeded = true; // Assuming guard construction succeeds

        // 9. Check if allocation blocked at limit
        snapshot.allocationBlockedAtLimit = !reaction::memory::StackMonitor::canAllocate(2048);
    }
    // 10. Exit guard scope (automatic via RAII)

    // 11. Check runtime allocation after release
    snapshot.runtimeAllowedAfterRelease = reaction::memory::StackMonitor::canAllocate(largeSize);

    return snapshot;
}

